def solve(challenge_phase, current_time):
    if challenge_phase not in ["draft", "active", "completed", "canceled"]:
        raise ValueError("Invalid challenge phase")

    if not isinstance(current_time, str):
        raise TypeError("current_time must be a string in ISO format")

    # Assuming current_time is in ISO 8601 format
    from datetime import datetime
    try:
        current_time_dt = datetime.fromisoformat(current_time)
    except ValueError:
        raise ValueError("current_time must be a valid ISO 8601 date string")

    # Core logic for phase transitions
    if challenge_phase == "draft":
        return "active" if current_time_dt >= datetime.now() else "draft"
    elif challenge_phase == "active":
        return "completed" if current_time_dt >= datetime.now() else "active"
    elif challenge_phase == "completed":
        return "completed"
    elif challenge_phase == "canceled":
        return "canceled"

    return None
